import csv

try:
    with open('trades.csv', 'r') as f:
        reader = csv.DictReader(f)
        buys = [row for row in reader if row['side'].upper() == 'BUY']

    totals = {}
    for row in buys:
        asset = row['asset']
        cost = float(row['qty']) * float(row['price'])
        totals[asset] = totals.get(asset, 0) + cost

    with open('summary.txt', 'w') as f:
        f.write('Buy Summary\n')
        f.write('=' * 30 + '\n')
        for asset, total in totals.items():
            f.write(f'{asset}: ${total:.2f}\n')

    print('Summary written to summary.txt')

except FileNotFoundError:
    print('Error: trades.csv not found')
except csv.Error as e:
    print(f'CSV error: {e}')
